const acts = items.map(i => i.json);
const now = new Date();

const startOfWeek = new Date(now);
startOfWeek.setDate(now.getDate() - now.getDay() + (now.getDay() === 0 ? -6 : 1));
startOfWeek.setHours(0,0,0,0);

const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
const startOfYear = new Date(now.getFullYear(), 0, 1);

const sportLabel = (t) => {
  const map = {Ride:'Rennrad',MountainBikeRide:'MTB',VirtualRide:'Virtual Ride',Run:'Laufen',Hike:'Wandern',Walk:'Gehen',Swim:'Schwimmen',WeightTraining:'Krafttraining',Workout:'Workout'};
  return map[t] || t;
};

const aggregate = (list) => {
  const byType = {};
  let totDist=0, totElev=0, totTime=0, totCount=0;
  for (const a of list) {
    totDist += a.distance||0;
    totElev += a.total_elevation_gain||0;
    totTime += a.moving_time||0;
    totCount++;
    const t = a.sport_type||a.type;
    if (!byType[t]) byType[t] = {count:0,distance:0,elevation:0,time:0,label:sportLabel(t)};
    byType[t].count++;
    byType[t].distance += a.distance||0;
    byType[t].elevation += a.total_elevation_gain||0;
    byType[t].time += a.moving_time||0;
  }
  return {
    count: totCount,
    distanceKm: Math.round(totDist/100)/10,
    elevationM: Math.round(totElev),
    timeMin: Math.round(totTime/60),
    byType: Object.entries(byType).sort((a,b)=>b[1].distance-a[1].distance).map(([type,d])=>({type,label:d.label,count:d.count,distanceKm:Math.round(d.distance/100)/10,elevationM:Math.round(d.elevation),timeMin:Math.round(d.time/60)}))
  };
};

const week = acts.filter(a => new Date(a.start_date) >= startOfWeek);
const month = acts.filter(a => new Date(a.start_date) >= startOfMonth);
const year = acts.filter(a => new Date(a.start_date) >= startOfYear);

const recent = acts.slice(0,5).map(a => ({
  id: a.id,
  name: a.name,
  type: a.sport_type||a.type,
  label: sportLabel(a.sport_type||a.type),
  date: a.start_date_local,
  distanceKm: Math.round((a.distance||0)/100)/10,
  elevationM: Math.round(a.total_elevation_gain||0),
  timeMin: Math.round((a.moving_time||0)/60),
  avgSpeedKmh: a.average_speed ? Math.round(a.average_speed*36)/10 : null,
  avgHr: a.average_heartrate ? Math.round(a.average_heartrate) : null,
  kudos: a.kudos_count||0,
  stravaUrl: 'https://www.strava.com/activities/'+a.id
}));

return [{ json: { week: aggregate(week), month: aggregate(month), year: aggregate(year), recent, updatedAt: new Date().toISOString() } }];

